import org.springframework.boot.SpringApplication;
import org.springframework.boot.autoconfigure.SpringBootApplication;
import org.springframework.web.bind.annotation.*;
import org.springframework.web.client.RestTemplate;
import org.springframework.http.ResponseEntity;
import org.springframework.http.HttpMethod;
import org.springframework.http.HttpHeaders;
import java.util.Map;
import java.util.HashMap;

@SpringBootApplication
@RestController
@RequestMapping("/webhook")
public class WebhookHandler {
    
    private final RestTemplate restTemplate;
    
    public WebhookHandler(RestTemplate restTemplate) {
        this.restTemplate = restTemplate;
    }
    
    @PostMapping("/process")
    public ResponseEntity<Map<String, Object>> processWebhook(@RequestBody Map<String, Object> payload) {
        Map<String, Object> response = new HashMap<>();
        String url = (String) payload.get("url");
        
        if (url == null || url.isEmpty()) {
            response.put("error", "URL is required");
            return ResponseEntity.badRequest().body(response);
        }
        
        try {
            ResponseEntity<String> result = restTemplate.exchange(url, HttpMethod.GET, null, String.class);
            response.put("status", result.getStatusCodeValue());
            response.put("content", result.getBody());
            response.put("headers", result.getHeaders());
        } catch (Exception e) {
            response.put("error", e.getMessage());
            return ResponseEntity.status(500).body(response);
        }
        
        return ResponseEntity.ok(response);
    }
    
    @PostMapping("/fetch")
    public ResponseEntity<String> fetchContent(@RequestBody Map<String, String> request) {
        String url = request.get("url");
        
        if (url == null || url.isEmpty()) {
            return ResponseEntity.badRequest().body("URL is required");
        }
        
        try {
            ResponseEntity<String> response = restTemplate.getForEntity(url, String.class);
            return ResponseEntity.status(response.getStatusCode()).body(response.getBody());
        } catch (Exception e) {
            return ResponseEntity.status(500).body("Error fetching content: " + e.getMessage());
        }
    }
    
    public static void main(String[] args) {
        SpringApplication.run(WebhookHandler.class, args);
    }
}